  ('Славолюб Пенкала', '{"description": "Друид-преподаватель, держит в Академии зверинец.", "status": "Преподаватель Академии", "name_en": "Slavolyub Penkala", "ai_art_name": "Славолюб Пенкала", "ai_art_url": "https://drive.google.com/file/d/14TeojScgjWf10-MAeMjywpJ1jou3Qo_u/view?usp=drivesdk", "source": "Мастер", "region": "Сиория", "group": "Преподаватели Академии", "age": "около 45", "skills": "друидизм; уход за магическими животными"}'::jsonb),
  ('Саймон Вирион', '{"description": "Бывший студент академии; вероятно, прежняя личность Дрипли, но сейчас потерял память.", "status": "Бывший ученик Академии", "name_en": "Simon Virion", "ai_art_name": "Саймон Вирион", "ai_art_url": "https://drive.google.com/file/d/1npULH4vnZ-Z9_zhqiEBdKs6WzdJaPPNU/view?usp=drivesdk", "source": "Мастер", "region": "Сиория", "group": "Академия Сиории", "age": "около 14", "appearances": "Игра 24\n- 2 петля, 25-30 странствий"}'::jsonb),
  ('Лайонел Вирион', '{"description": "Отец Саймона Вириона и создатель Дрипли; эксперт в алхимии, надеется пробудить душу сына в слизи.", "status": "Преподаватель Академии", "name_en": "Lionel Virion", "ai_art_name": "Лайонел Вирион", "ai_art_url": "https://drive.google.com/file/d/14isHwwyOD4oMTgms-P30CWumDbcxgxVc/view?usp=drivesdk", "source": "Мастер", "region": "Сиория", "group": "Преподаватели Академии", "age": "около 50", "skills": "алхимия; эксперименты со слизью/душой", "appearances": "Игра 3\n- 1 петля, 1 странствий\nИгра 11\n- 1 петля, 16 странствий\n- 2 петля, 1 странствий\nИгра 12\n- 2 петля, 1 странствий\n2 петля, 2 странствий\nИгра 30\n- 3 петля, 6-8 странствий\nИгра 49\n- 4 петля, 19 странствий\nИгра 60\n- 5 петля, 1-6 странствий"}'::jsonb),
  ('Акоджа Строуз', '{"description": "Прилежная староста и простолюдинка в элитной Академии, старающаяся заслужить уважение дисциплиной и успехами.", "status": "Ученик Академии, 3 курс", "name_en": "Akoja Stroze", "art_name": "Акоджа Строуз", "art_url": "https://drive.google.com/file/d/12UpdVy4cO9P_54sTxTy-ZKZAuDi0o37z/view?usp=drive_link", "ai_art_name": "Акоджа Строуз", "ai_art_url": "https://drive.google.com/file/d/1kuQQpacAFHuYDXPyGDT89isDEJyRAC1N/view?usp=drivesdk", "wiki_url": "https://mother-of-learning.fandom.com/wiki/Akoja_Stroze", "source": "Канон", "region": "Сиория", "group": "Академия Сиории", "age": "15", "skills": "организация; дисциплина; староста группы", "appearances": "Игра 57\n- 4 петля, 28-30 странствий", "old_notes": "Староста группы Зориана; прилежная, дисциплинированная, аккуратная; каштановые волосы, очки, карие глаза."}'::jsonb),
  ('Бенисек', '{"description": "Пухлый, ленивый любитель сплетен из богатой торговой семьи; оптимистичный, жизнерадостный, но непопулярный у девушек.", "status": "Ученик Академии, 3 курс", "name_en": "Benisek", "art_name": "Бенисек", "art_url": "https://drive.google.com/file/d/1yr_3VKbMx9vdTU1yWU6NXQsbdk936rsM/view?usp=drive_link", "ai_art_name": "Бенисек", "ai_art_url": "https://drive.google.com/file/d/1Cf_Am2h6OKlMNAmS0_-WAjXTfzX4RP-z/view?usp=drivesdk", "wiki_url": "https://mother-of-learning.fandom.com/wiki/Benisek", "source": "Канон", "region": "Сиория", "group": "Академия Сиории", "age": "15", "skills": "сплетни; социальная осведомлённость", "appearances": "Игра 6\n- 1 петля, 13-14 странствий\nИгра 10\n- 1 петля, 14 странствий\nИгра 20\n- 2 петля, 20 странствий \nИгра 29\n- 3 петля, 6-8 странствий\nИгра 35\n- 3 петля, 17-24 странствий\nИгра 36\n- 3 петля, 30 странствий\nИгра 56\n- 4 петля, 27-30 странствий\nИгра 57\n- 4 петля, 28-30 странствий"}'::jsonb),
  ('Неолу (Неолума-Ману Ильятир)', '{"description": "Наивная и разговорчивая ученица из дома Ильятир; мечтательница, легко верит в необычное и отправлена в Сиорию ради безопасности.", "status": "Ученик Академии, 3 курс", "name_en": "Neoluma-Manu Iljatir", "art_name": "Неолу (Неолума-Ману Ильятир).webp", "art_url": "https://drive.google.com/open?id=1AErZ3fDox_MrVYVAA0ldYxVX_jLRf9zX&usp=drive_copy", "ai_art_name": "Неолу", "ai_art_url": "https://drive.google.com/file/d/1aDWNwpivwBo-uMrmBEwW6DPpGtbHYcc0/view?usp=drivesdk", "wiki_url": "https://mother-of-learning.fandom.com/wiki/Neoluma-Manu_Iljatir", "source": "Канон", "region": "Сиория", "group": "Академия Сиории", "age": "15", "skills": "общение; социальность; возможная связь дома с прорицанием", "dm_notes": "Дом Ильятир связан с прорицаниями.", "old_notes": "Наивная и разговорчивая мечтательница с Кольтемара; смуглая кожа, светлые волосы, голубые глаза, татуировки на лице."}'::jsonb),
  ('Рейни', '{"description": "Скрытная и сдержанная рыжеволосая ученица, старающаяся стать сильнее вдали от семьи.", "status": "Ученик Академии, 3 курс", "name_en": "Raynie", "art_name": "Рейни", "art_url": "https://drive.google.com/file/d/14OVIITm-5kW4fz8QMoS-MB1w23kkp1f9/view?usp=drive_link", "ai_art_name": "Рейни", "ai_art_url": "https://drive.google.com/file/d/1mDtF3S7iq4WnRR1A1z8odTj9_np3GbCm/view?usp=drivesdk", "wiki_url": "https://mother-of-learning.fandom.com/wiki/Raynie", "source": "Канон", "region": "Сиория", "group": "Академия Сиории", "age": "15", "skills": "скрытность; самоконтроль", "dm_notes": "Дочь вождя; семейная политическая проблема с наследованием.", "old_notes": "Рыжеволосая красавица-переводница; вежливая, сдержанная и скрытная; близко дружит с Кианой."}'::jsonb),
  ('Киана', '{"description": "Подруга Рейни; привлекательная, уверенная, общительная девушка с длинными чёрными волосами.", "status": "Ученик Академии, 3 курс", "name_en": "Kiana", "art_name": "Киана", "art_url": "https://drive.google.com/file/d/138y5r0o1a_2Xmp3nQCW0L6GOIW4lWhYH/view?usp=drive_link", "ai_art_name": "Киана", "ai_art_url": "https://drive.google.com/file/d/1CJlIyH2OX--Wr-nmMbTpgxbDrwkMIdnE/view?usp=drivesdk", "wiki_url": "https://mother-of-learning.fandom.com/wiki/Kiana", "source": "Канон", "region": "Сиория", "group": "Академия Сиории", "age": "15", "skills": "социальность; дружба с Рейни"}'::jsonb),
  ('Джейд Витэльсин', '{"description": "Болтушка и собирательница сплетен; из богатого дома Витэльсин; светлые волосы, голубые глаза, следит за модой.", "status": "Ученик Академии, 3 курс", "name_en": "Jade", "art_name": "Джейд Витэльсин", "art_url": "https://drive.google.com/file/d/1H4kwB_jSvBwVN262SGxS6wTzz4PUexrI/view?usp=drive_link", "ai_art_name": "Джейд Витэльсин", "ai_art_url": "https://drive.google.com/file/d/1ZFofF0MN2Ftc2QRguPGcq1WbV-LShzYF/view?usp=drivesdk", "wiki_url": "https://mother-of-learning.fandom.com/wiki/Jade", "source": "Канон", "region": "Сиория", "group": "Академия Сиории", "age": "15", "skills": "сплетни; светская мода"}'::jsonb),
  ('Элси', '{"description": "Подруга Джейд, Неолу, Майи и Кианы; любит беседы, подслушивание и ручное создание вещей без магии.", "status": "Ученик Академии, 3 курс", "name_en": "Elsie", "ai_art_name": "Элси", "ai_art_url": "https://drive.google.com/file/d/1SFCiqZO8UEgup-mxUZFx8Kh5a-pJ6Eg_/view?usp=drivesdk", "wiki_url": "https://mother-of-learning.fandom.com/wiki/Elsie", "source": "Канон", "region": "Сиория", "group": "Академия Сиории", "age": "15", "skills": "сплетни; подслушивание; ручное создание вещей"}'::jsonb),
